SET NAMES utf8mb4;
SET FOREIGN_KEY_CHECKS = 0;

DROP TABLE IF EXISTS `metricas_likert`;
CREATE TABLE `metricas_likert` (
  `Año` INT,
  `SEDE` VARCHAR(255),
  `CARRERA` VARCHAR(255),
  `Categoria` VARCHAR(255),
  `Pregunta` VARCHAR(255),
  `N_Respuestas` DOUBLE,
  `Frec_1` DOUBLE,
  `Frec_2` DOUBLE,
  `Frec_3` DOUBLE,
  `Frec_4` DOUBLE,
  `Frec_5` DOUBLE,
  `Frec_T2B` DOUBLE,
  `Pct_1` DOUBLE,
  `Pct_2` DOUBLE,
  `Pct_3` DOUBLE,
  `Pct_4` DOUBLE,
  `Pct_5` DOUBLE,
  `Top_2_Box` DOUBLE,
  `Promedio_1_5` DOUBLE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;


DROP TABLE IF EXISTS `metricas_dicotomicas`;
CREATE TABLE `metricas_dicotomicas` (
  `Año` INT,
  `SEDE` VARCHAR(255),
  `CARRERA` VARCHAR(255),
  `Categoria` VARCHAR(255),
  `Pregunta` VARCHAR(255),
  `N_Respuestas` DOUBLE,
  `Frec_Si` DOUBLE,
  `Frec_No` DOUBLE,
  `Pct_Si` DOUBLE,
  `Pct_No` DOUBLE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;


DROP TABLE IF EXISTS `metricas_valores_sebastianos`;
CREATE TABLE `metricas_valores_sebastianos` (
  `Año` INT,
  `SEDE` VARCHAR(255),
  `CARRERA` VARCHAR(255),
  `Valor_Sebastiano` VARCHAR(255),
  `N_Respuestas` INT,
  `Menciones` DOUBLE,
  `Pct_Menciones` DOUBLE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;


SET FOREIGN_KEY_CHECKS = 1;
